// Input: m×n matrix A representing T: ℝⁿ → ℝᵐ
// Output: Basis vectors for Ker(T)

FUNCTION findKernelBasis(A, m, n):
 // Augment with zero vector
 augmented ← createAugmentedMatrix(A, m, n)

 // Row reduce to echelon form
 rref ← reducedRowEchelonForm(augmented)

 // Identify free variables
 pivotColumns ← findPivots(rref)
 freeVariables ← [0..n-1] - pivotColumns

 basis ← empty list

 // For each free variable, create basis vector
 FOR each f IN freeVariables:
 v ← zeros(n)
 v[f] ← 1

 // Set pivot variables based on rref
 FOR each p IN pivotColumns:
 row ← findRowWithPivotInColumn(p, rref)
 v[p] ← -rref[row][f]

 basis.append(v)

 RETURN basis

// Check if T is one-to-one: Ker(T) = {0}
// Equivalent to: rank = dimension of domain (for square)

FUNCTION isOneToOne(A, m, n):
 rank ← computeRank(A, m, n)

 // For T: V→W
 // One-to-one iff dim(Ker) = 0
 // By Rank-Nullity: dim(Ker) = n - rank

 nullity ← n - rank

 IF nullity == 0 THEN
 RETURN true // One-to-one
 ELSE
 RETURN false // Not one-to-one, Ker has dimension nullity

FUNCTION computeRank(A, m, n):
 // Use Gaussian elimination
 U ← upperTriangularForm(A)

 rank ← 0
 FOR i ← 0 TO min(m,n)-1:
 IF U[i][i] ≠ 0 THEN
 rank ← rank + 1
 RETURN rank

// Find inverse of n×n matrix A
// T is non-singular iff inverse exists

FUNCTION findInverse(A, n):
 // Create augmented matrix [A | I]
 augmented ← createAugmented(A, n)

 // Apply Gauss-Jordan elimination
 FOR col ← 0 TO n-1:
 // Find pivot row
 pivotRow ← findNonZeroPivot(augmented, col, col)
 IF pivotRow == -1 THEN
 RETURN null // Matrix is singular, no inverse

 // Swap rows if needed
 IF pivotRow ≠ col THEN
 swapRows(augmented, col, pivotRow)

 // Scale pivot row to make pivot 1
 pivot ← augmented[col][col]
 scaleRow(augmented, col, 1/pivot)

 // Eliminate other rows
 FOR row ← 0 TO n-1:
 IF row ≠ col THEN
 factor ← augmented[row][col]
 eliminateRow(augmented, row, col, factor)

 // Extract inverse from right half
 inverse ← extractRightHalf(augmented, n)
 RETURN inverse

